import datetime
from elasticsearch import Elasticsearch
from elasticsearch.helpers import bulk

class CentralLoggerAndSearch:
    def __init__(self, host='localhost', port=9200, index_prefix='my_app'):
        self.es = Elasticsearch([{'host': host, 'port': port}])
        self.log_index_name = f"{index_prefix}_logs"
        self.doc_index_name = f"{index_prefix}_documents"
        self._ensure_indices_exist()

    def _ensure_indices_exist(self):
        """Ensures the log and document indices exist, creating them if necessary."""
        if not self.es.indices.exists(index=self.log_index_name):
            self.es.indices.create(index=self.log_index_name, body={
                "mappings": {
                    "properties": {
                        "timestamp": {"type": "date"},
                        "level": {"type": "keyword"},
                        "message": {"type": "text"},
                        "service": {"type": "keyword"},
                        "user_id": {"type": "keyword"}
                    }
                }
            })
            print(f"Created index: {self.log_index_name}")

        if not self.es.indices.exists(index=self.doc_index_name):
            self.es.indices.create(index=self.doc_index_name, body={
                "mappings": {
                    "properties": {
                        "title": {"type": "text", "analyzer": "standard"},
                        "content": {"type": "text", "analyzer": "standard"},
                        "tags": {"type": "keyword"},
                        "author": {"type": "keyword"},
                        "timestamp": {"type": "date"}
                    }
                }
            })
            print(f"Created index: {self.doc_index_name}")

    def log(self, level, message, service="general", user_id=None, extra_data=None):
        """
        Logs a message to Elasticsearch.
        """
        log_entry = {
            "timestamp": datetime.datetime.utcnow(),
            "level": level,
            "message": message,
            "service": service
        }
        if user_id:
            log_entry["user_id"] = user_id
        if extra_data and isinstance(extra_data, dict):
            log_entry.update(extra_data)

        try:
            self.es.index(index=self.log_index_name, document=log_entry)
            # print(f"Logged: [{level}] {message}")
        except Exception as e:
            print(f"Error logging message: {e}")

    def index_document(self, doc_id, title, content, tags=None, author=None):
        """
        Indexes a document for full-text search.
        """
        document = {
            "title": title,
            "content": content,
            "timestamp": datetime.datetime.utcnow()
        }
        if tags:
            document["tags"] = tags if isinstance(tags, list) else [tags]
        if author:
            document["author"] = author

        try:
            self.es.index(index=self.doc_index_name, id=doc_id, document=document)
            # print(f"Indexed document: {title} (ID: {doc_id})")
        except Exception as e:
            print(f"Error indexing document {doc_id}: {e}")

    def bulk_index_documents(self, documents):
        """
        Indexes multiple documents using Elasticsearch's bulk API.
        documents should be a list of dicts, each containing:
        - '_id': unique ID for the document
        - 'title': document title
        - 'content': document content
        - 'tags': optional list of tags
        - 'author': optional author
        """
        actions = []
        for doc in documents:
            source = {
                "title": doc['title'],
                "content": doc['content'],
                "timestamp": datetime.datetime.utcnow()
            }
            if 'tags' in doc:
                source['tags'] = doc['tags']
            if 'author' in doc:
                source['author'] = doc['author']

            action = {
                "_index": self.doc_index_name,
                "_id": doc['_id'],
                "_source": source
            }
            actions.append(action)

        try:
            success, failed = bulk(self.es, actions)
            # print(f"Bulk indexed {success} documents, {len(failed)} failed.")
            if failed:
                for item in failed:
                    print(f"Failed to index document: {item}")
            return success, failed
        except Exception as e:
            print(f"Error during bulk indexing: {e}")
            return 0, actions # All actions considered failed

    def search_documents(self, query, fields=None, size=10, highlight=True):
        """
        Performs a full-text search on indexed documents.
        """
        search_body = {
            "query": {
                "multi_match": {
                    "query": query,
                    "fields": fields if fields else ["title^3", "content"] # Boost title
                }
            }
        }
        if highlight:
            search_body["highlight"] = {
                "fields": {
                    "title": {},
                    "content": {}
                },
                "pre_tags": ["<strong>"],
                "post_tags": ["</strong>"]
            }

        try:
            res = self.es.search(index=self.doc_index_name, body=search_body, size=size)
            return res['hits']['hits']
        except Exception as e:
            print(f"Error searching documents: {e}")
            return []

    def get_logs(self, query=None, service=None, level=None, start_time=None, end_time=None, size=10, sort_order="desc"):
        """
        Retrieves logs, with optional filtering.
        """
        must_clauses = []
        if query:
            must_clauses.append({"match": {"message": query}})
        if service:
            must_clauses.append({"term": {"service.keyword": service}})
        if level:
            must_clauses.append({"term": {"level.keyword": level}})

        range_clause = {}
        if start_time:
            range_clause["gte"] = start_time.isoformat()
        if end_time:
            range_clause["lte"] = end_time.isoformat()

        if range_clause:
            must_clauses.append({"range": {"timestamp": range_clause}})

        search_body = {
            "query": {
                "bool": {
                    "must": must_clauses if must_clauses else [{"match_all": {}}]
                }
            },
            "sort": [{"timestamp": {"order": sort_order}}]
        }

        try:
            res = self.es.search(index=self.log_index_name, body=search_body, size=size)
            return res['hits']['hits']
        except Exception as e:
            print(f"Error getting logs: {e}")
            return []

    def get_log_aggregations(self, field, interval="hour", start_time=None, end_time=None, top_n=5):
        """
        Performs aggregations on log data.
        Example field: "level.keyword", "service.keyword", "user_id.keyword"
        """
        aggs_body = {
            "log_counts_over_time": {
                "date_histogram": {
                    "field": "timestamp",
                    "fixed_interval": f"1{interval}" # e.g., "1h", "1d"
                },
                "aggs": {
                    "top_terms": {
                        "terms": {
                            "field": field,
                            "size": top_n
                        }
                    }
                }
            }
        }

        must_clauses = []
        range_clause = {}
        if start_time:
            range_clause["gte"] = start_time.isoformat()
        if end_time:
            range_clause["lte"] = end_time.isoformat()
        if range_clause:
            must_clauses.append({"range": {"timestamp": range_clause}})

        search_body = {
            "size": 0, # We only want aggregations
            "aggs": aggs_body
        }
        if must_clauses:
            search_body["query"] = {"bool": {"must": must_clauses}}

        try:
            res = self.es.search(index=self.log_index_name, body=search_body)
            return res['aggregations']
        except Exception as e:
            print(f"Error getting log aggregations: {e}")
            return {}

    def delete_index(self, index_name):
        """Deletes an index."""
        try:
            if self.es.indices.exists(index=index_name):
                self.es.indices.delete(index=index_name)
                print(f"Deleted index: {index_name}")
            else:
                print(f"Index {index_name} does not exist.")
        except Exception as e:
            print(f"Error deleting index {index_name}: {e}")

    def close(self):
        """Closes the Elasticsearch connection."""
        self.es.close()
        print("Elasticsearch connection closed.")


